const jarvisLog = (level, message, meta = {}) => {
  const levels = { debug: 0, info: 1, warn: 2, error: 3 };
  const configLevel = ($env.LOG_LEVEL || 'info').toLowerCase();
  if (levels[level] >= (levels[configLevel] ?? 1)) {
    console[level === 'error' ? 'error' : level === 'warn' ? 'warn' : 'log'](
      JSON.stringify({
        timestamp: new Date().toISOString(),
        level, traceId: $json.traceId || 'unknown',
        workflow: 'error-handler', message, meta
      })
    );
  }
};

const error = $json.error || {};
const errorMessage = error.message || error.error || $json.message || 'Unknown error';
const workflowId = $json.workflow?.id || $json.workflow || 'unknown';
const executionId = $json.execution?.id || 'unknown';

let traceId = 'no-trace';
try {
  const runData = $json.execution?.data?.resultData?.runData || {};
  const normalizeNode = runData['Normalize Request'] || runData['Input'] || {};
  const firstData = normalizeNode[0]?.data?.main?.[0]?.[0]?.json;
  if (firstData?.traceId) traceId = firstData.traceId;
  else if (firstData?.sessionId) traceId = firstData.sessionId;
} catch (e) {
  traceId = 'err_' + Date.now();
}

jarvisLog('error', 'Workflow failed', { workflow: workflowId, executionId, error: errorMessage });

let userMessage;
if (errorMessage && errorMessage.includes('RATE_LIMIT_EXCEEDED')) {
  userMessage = '⏳ Too many requests. Please wait a moment before trying again.';
} else {
  userMessage = '⚠️ Something went wrong (' + traceId + '). Please try again or check logs.';
}

return [{ json: { ...$input.item.json, errorMessage: userMessage, errorLogged: true, traceId } }];
